import { Checkbox, Input, Modal, Popover } from 'antd';
import { CardLayoutPreview, InternalPopover, PopoverButton, StyledDropdown, StyledPopMarkdown } from 'src/component';
import { CardTextArea, CardTextAreaRef, CardTextInput } from '../input-text';
import { useCard, useLanguage, useSetting } from 'src/service';
import { useShallow } from 'zustand/react/shallow';
import { forwardRef, useImperativeHandle, useMemo, useRef, useState } from 'react';
import { CanvasConst, DEFAULT_PENDULUM_SIZE, PendulumSizeMap, CheckboxChangeEvent, getDefaultCoordinateMap } from 'src/model';
import { ApartmentOutlined } from '@ant-design/icons';
import { getFrameButtonList } from '../const';
import styled from 'styled-components';
import { isJsonObjectEqual, resolveFrameStyle } from 'src/util';
import {
    FrameBehaviorSettingPanel,
    FrameCoordinatePanel,
    FrameCoordinatePanelRef,
    FrameLayoutSettingPanel,
} from '../frame-setting-panel';
import { FlagPresentationList } from '../../common';

const {
    width,
    height,
} = CanvasConst;

type BottomFrameOptionGridRef = {
    focus: () => void,
};

const StyledFrameSettingModal = styled(Modal)`
    .ant-modal-content .ant-modal-body {
        padding: 0;
    }
`;
const StyledPendulumFrameInputContainer = styled.div`
    display: inline-flex;
    cursor: pointer;
    vertical-align: bottom;
    box-shadow: var(--bs-button);
    border-radius: var(--br-lg);
    background-color: var(--main-level-4);
    align-items: center;
    &:focus-visible {
        outline: 2px solid var(--focus);
    }
    .flag-list-indicator {
        box-shadow: 0 0 0 var(--bw) var(--sub-level-1) inset;
        padding: var(--spacing-xs);
        border-radius: 0 var(--br-lg) var(--br-lg) 0;
        &:empty:before {
            content: "\\200B";
        }
    }
    .pendulum-frame-label {
        display: inline-block;
        background: var(--main-level-4);
        border: var(--bw) solid var(--sub-level-1);
        border-right: none;
        padding: var(--spacing-px) var(--spacing-xs);
        border-radius: var(--br-lg) 0 0 var(--br-lg);
        line-height: 2; // Alignment
        &:last-child {
            border-radius: var(--br-lg);
            border-right: var(--bw) solid var(--sub-level-1);
        }
    }
    .card-layout-preview-container {
        line-height: 0;
        border: var(--bw) solid var(--sub-level-1);
        overflow: hidden;
    }
`;
const StyledPendulumInputContainer = styled.div`
    display: grid;
    grid-template-columns: 1fr 1fr;
    column-gap: var(--spacing-sm);
    row-gap: var(--spacing-sm);
    .red-scale {
        color: var(--sub-red-scale);
    }
    .blue-scale {
        color: var(--sub-blue-scale);
    }
    .pendulum-option-container {
        display: flex;
        flex-wrap: wrap;
        align-items: center;
    }
    .pendulum-option {
        display: grid;
        grid-template-columns: var(--width-label) 1fr;
        align-items: center;
        .pendulum-frame-input,
        .pendulum-checkbox {
            flex: 0 0 auto;
        }
        .mirror-scale {
            /** Alignment **/
            line-height: 32px;
            align-items: center;
            .ant-checkbox {
                transform: translateY(-1px); // Alignment, but why?
            }
        }
    }
    .frame-layout-button {
        vertical-align: bottom;
        flex: 0 0 auto;
        margin: 0;
        margin-right: var(--spacing);
    }
    .joined-row {
        position: relative;
        grid-column: span 2;
        .standalone-label {
            min-width: 0;
            width: unset;
            padding-left: var(--spacing-antd);
        }
        .pendulum-checkbox {
            display: inline-block;
            /** Alignment **/
            width: var(--width-label);
            /** Alignment **/
            line-height: 32px;
            text-align: right;
            font-weight: 500;
            margin-right: 0;
            padding-right: var(--spacing);
            > span {
                padding-right: 0;
            }
        }
        .pendulum-checkbox-placeholder {
            display: inline-block;
            /** Alignment **/
            width: var(--width-label);
        }
        .pendulum-frame-input {
            margin-right: var(--spacing);
        }
        .pendulum-size {
            display: inline-block;
            margin-right: var(--spacing);
            .pendulum-size-button {
                margin: 0;
            }
        }
        .ant-checkbox-wrapper + .ant-checkbox-wrapper {
            margin-left: 0;
        }
    }
`;

export type PendulumInputGroupRef = {
    setValue: (value: {
        pendulumEffect?: string,
        overlay?: string,
        overlayData?: string,
        overlaySource?: string,
        overlayCrop?: Partial<ReactCrop.Crop>,
    }) => void,
}
export type PendulumInputGroup = {
    softMode: boolean,
    showCreativeOption: boolean,
    showExtraDecorativeOption: boolean,
}
    & Pick<CardTextInput, 'onTakePicker'>
    & Pick<FrameLayoutSettingPanel, 'receivingCanvas' | 'onFrameChange' | 'onSourceLoaded' | 'onTainted' | 'onCropChange'>;
export const PendulumInputGroup = forwardRef<PendulumInputGroupRef, PendulumInputGroup>(({
    softMode,
    showCreativeOption,
    showExtraDecorativeOption,
    receivingCanvas,
    onTakePicker,
    onFrameChange,
    onCropChange,
    onTainted,
    onSourceLoaded,
}, ref) => {
    const language = useLanguage();
    const {
        isPendulum,
        frame,
        foil,
        leftFrame, rightFrame,
        pendulumFrame, pendulumRightFrame,
        effectBackground, pendulumEffectBackground,
        pendulumScaleBlue,
        pendulumScaleRed,
        pendulumSize,
        coordinateMap,
        dyeList,
        flag,
        setCard,
        getUpdater,
    } = useCard(useShallow(({
        card: {
            isPendulum,
            frame,
            foil,
            leftFrame, rightFrame,
            pendulumFrame, pendulumRightFrame,
            pendulumScaleBlue,
            pendulumScaleRed,
            pendulumSize,
            effectStyle,
            pendulumStyle,
            coordinateMap,
            dyeList,
            flag,
        },
        setCard,
        getUpdater,
    }) => ({
        isPendulum,
        frame,
        foil,
        leftFrame, rightFrame,
        pendulumFrame, pendulumRightFrame,
        pendulumScaleBlue,
        pendulumScaleRed,
        pendulumSize,
        effectBackground: effectStyle.background,
        pendulumEffectBackground: pendulumStyle.background,
        coordinateMap,
        dyeList,
        flag,
        setCard,
        getUpdater,
    })));
    const {
        mirrorPendulumScale,
        updateSetting,
    } = useSetting(useShallow(({
        setting: { mirrorPendulumScale },
        updateSetting,
    }) => ({
        mirrorPendulumScale,
        updateSetting,
    })));
    const containerRef = useRef<HTMLDivElement>(null);
    const frameBlenderRef = useRef<BottomFrameOptionGridRef>(null);
    const frameCoordinateRef = useRef<FrameCoordinatePanelRef>(null);
    const pendulumEffectInputRef = useRef<CardTextAreaRef>(null);
    const [frameBlenderVisible, setFrameBlenderVisible] = useState(false);
    const [frameCoordinateVisible, setFrameCoordinateVisible] = useState(false);
    const changeToPendulum = (e: CheckboxChangeEvent) => setCard(currentCard => {
        const willBecomePendulum = e.target.checked;
        /** It is rather not desirable to seemingly reduce opacity of pendulum frame, even though it looks closer to real card */
        // const currentOpacity = currentCard.opacity;
        // const nextOpacity = willBecomePendulum && (currentOpacity.pendulum ?? 100) !== 85
        //     ? { ...currentOpacity, pendulum: 85 }
        //     : currentOpacity;

        return {
            ...currentCard,
            // opacity: nextOpacity,
            isPendulum: willBecomePendulum,
        };
    });
    const onRedScaleChange = useMemo(() => getUpdater('pendulumScaleRed'), [getUpdater]);
    const onBlueScaleChange = useMemo(() => getUpdater('pendulumScaleBlue'), [getUpdater]);
    const onPendulumSizeChange = useMemo(() => getUpdater('pendulumSize'), [getUpdater]);
    const changePendulumEffect = useMemo(() => getUpdater('pendulumEffect', undefined, 'debounce'), [getUpdater]);

    const pendulumSizeList = useMemo(() => Object.values(PendulumSizeMap).map(({ key, labelKey }) => ({
        label: language[labelKey],
        value: key,
    })), [language]);
    const frameList = useMemo(() => getFrameButtonList('both')
        .filter(entry => {
            return showExtraDecorativeOption || entry.edition === 'normal';
        }),
        [showExtraDecorativeOption],
    );

    useImperativeHandle(ref, () => ({
        setValue: ({ pendulumEffect }) => {
            if (pendulumEffect) pendulumEffectInputRef.current?.setValue(pendulumEffect);
        }
    }));

    const layoutState = {
        frame,
        topLeftFrame: leftFrame,
        topRightFrame: rightFrame,
        bottomLeftFrame: pendulumFrame,
        bottomRightFrame: pendulumRightFrame,
        effectBackground,
        pendulumEffectBackground,
    };
    const advanceLayoutPreviewHeight = 30; // Alignment with frame input
    const flagList = flag
        .map((entry, index) => {
            const target = FlagPresentationList[index];

            if (entry !== 0 && target) return <li key={target.labelKey}>
                {target.valueDisplay(language, entry)}
            </li>;
            return null;
        })
        .filter(entry => entry != null);

    return <StyledPendulumInputContainer
        className="pendulum-input"
    >
        <div className="joined-row pendulum-option">
            <div className="pendulum-checkbox">
                <Checkbox
                    onChange={changeToPendulum}
                    checked={isPendulum}
                >{language['input.pendulum.label']}</Checkbox>
            </div>
            <div className="pendulum-option-container">
                <StyledFrameSettingModal
                    visible={frameBlenderVisible}
                    onCancel={() => setFrameBlenderVisible(false)}
                    width={613}
                    forceRender
                    closable={false}
                    footer={null}
                    className="global-input-overlay frame-blender-overlay layout-picker-overlay"
                >
                    <FrameLayoutSettingPanel ref={frameBlenderRef}
                        isPendulum={isPendulum}
                        frameList={frameList}
                        pendulumFrame={pendulumFrame}
                        onTainted={onTainted}
                        onCropChange={onCropChange}
                        onSourceLoaded={onSourceLoaded}
                        receivingCanvas={receivingCanvas}
                        onFrameChange={onFrameChange}
                        onCancel={() => {
                            setFrameBlenderVisible(false);
                            containerRef.current?.focus();
                        }}
                    />
                    <FrameBehaviorSettingPanel />
                </StyledFrameSettingModal>
                <Modal
                    visible={frameCoordinateVisible}
                    onCancel={() => setFrameCoordinateVisible(false)}
                    width={380}
                    closable={false}
                    footer={null}
                    className="global-input-overlay frame-coordinate-overlay layout-picker-overlay"
                >
                    <FrameCoordinatePanel
                        ref={frameCoordinateRef}
                    />
                </Modal>
                {showCreativeOption && <StyledPendulumFrameInputContainer ref={containerRef}
                    className="pendulum-frame-input"
                    tabIndex={0}
                    onClick={() => setFrameBlenderVisible(true)}
                    onKeyDown={e => {
                        if (e.key === 'ArrowDown' || e.key === 'Enter' || e.key === '  ') {
                            setFrameBlenderVisible(true);
                            /** Popover takes time to mount / become visible */
                            setTimeout(() => {
                                frameBlenderRef.current?.focus();
                            }, 200);

                            return false;
                        }
                    }}
                >
                    <span className="pendulum-frame-label">
                        {language['input.advanced-frame.label']}
                    </span>
                    <div className="card-layout-preview-container">
                        <CardLayoutPreview
                            width={Math.round(advanceLayoutPreviewHeight * width / height)}
                            height={advanceLayoutPreviewHeight}
                            isPendulum={isPendulum}
                            resolvedLayoutState={resolveFrameStyle(layoutState, isPendulum)}
                            tabIndex={-1}
                            dyeList={dyeList}
                            foil={foil}
                            language={language}
                        />
                    </div>
                    <div className="flag-list-indicator">
                        {flagList.length > 0
                            ? <InternalPopover
                                content={<StyledPopMarkdown>
                                    {language['input.flag.effective.label']}
                                    <ul>{flagList}</ul>
                                </StyledPopMarkdown>}
                            >
                                <ApartmentOutlined />
                            </InternalPopover>
                            : null}
                    </div>
                </StyledPendulumFrameInputContainer>}
                {showCreativeOption && <PopoverButton
                    tabIndex={0}
                    $softMode={softMode}
                    $active={!isJsonObjectEqual(coordinateMap, getDefaultCoordinateMap())}
                    className="frame-layout-button"
                    onClick={() => setFrameCoordinateVisible(true)}
                    onKeyDown={e => {
                        if (e.key === 'ArrowDown' || e.key === 'Enter' || e.key === '  ') {
                            setFrameCoordinateVisible(true);

                            return false;
                        }
                    }}
                >
                    <div className="button-label">
                        {language['input.frame-coordinate.label']}
                    </div>
                </PopoverButton>}
                {(isPendulum && showCreativeOption) && <div className="pendulum-size">
                    <Popover key="color-picker"
                        overlayClassName="global-input-overlay font-picker-overlay"
                        content={<div className="overlay-event-absorber">
                            <StyledDropdown.Container>
                                {pendulumSizeList.map(({ value, label }) => {
                                    return <StyledDropdown.Option key={value}
                                        className={pendulumSize === value ? 'menu-active' : ''}
                                        onClick={() => {
                                            onPendulumSizeChange(value);
                                        }}
                                    >
                                        {label}
                                    </StyledDropdown.Option>;
                                })}
                            </StyledDropdown.Container>
                        </div>}
                        placement="bottomLeft"
                    >
                        <PopoverButton
                            className="pendulum-size-button"
                            $softMode={softMode}
                            $active={pendulumSize !== DEFAULT_PENDULUM_SIZE}
                        >
                            {language[PendulumSizeMap[pendulumSize].labelKey]}
                        </PopoverButton>
                    </Popover>
                </div>}
                {(isPendulum && showCreativeOption)
                    && <Checkbox
                        className="mirror-scale"
                        onChange={e => {
                            const willMirror = e.target.checked;

                            updateSetting({ mirrorPendulumScale: willMirror });
                            if (willMirror) onRedScaleChange(pendulumScaleBlue);
                        }}
                        checked={mirrorPendulumScale}
                    >
                        {language['input.mirror-scale.label']}
                    </Checkbox>}
            </div>
        </div>
        {isPendulum && <>
            <div>
                <Input
                    addonBefore={<span>
                        {language['input.scale.label'](
                            <span key="blue-scale" className="blue-scale">
                                {language['input.scale.blue.label']}
                            </span>
                        )}
                    </span>}
                    value={pendulumScaleBlue}
                    allowClear
                    onChange={e => {
                        onBlueScaleChange(e);
                        if (mirrorPendulumScale) onRedScaleChange(e);
                    }}
                />
            </div>
            <div>
                <Input
                    addonBefore={<span>
                        {language['input.scale.label'](
                            <span key="red-scale" className="red-scale">
                                {language['input.scale.red.label']}
                            </span>
                        )}
                    </span>}
                    value={pendulumScaleRed}
                    allowClear
                    onChange={e => {
                        if (mirrorPendulumScale) onBlueScaleChange(e);
                        onRedScaleChange(e);
                    }}
                />
            </div>
            <div className="joined-row">
                {/** Explicit label does not looks too good */}
                {/* <StandaloneLabel className="standalone-label">Pendulum Effect</StandaloneLabel> */}
                <CardTextArea ref={pendulumEffectInputRef}
                    id="pendulum-effect"
                    allowHotkey
                    defaultValue={useCard.getState().card.pendulumEffect}
                    onChange={changePendulumEffect}
                    onTakePicker={onTakePicker}
                    autoSize={{
                        minRows: 5,
                    }}
                />
            </div>
        </>}
    </StyledPendulumInputContainer>;
});